var zhr = SporadicMeteorMgr.getZHR();
core.debug("Current meteor rate: " + zhr + " meteors per hour");

if(zhr < 5) {
    core.debug("Low meteor activity");
} else if(zhr > 50) {
    core.debug("High meteor activity - good for observing!");
}

// Set low meteor activity for a quiet night
SporadicMeteorMgr.setZHR(5);

// Set high activity for a meteor-rich display
SporadicMeteorMgr.setZHR(50);

// Disable sporadic meteors completely
SporadicMeteorMgr.setZHR(0);

// Get the new value
var newZHR = SporadicMeteorMgr.getZHR();
core.debug("New meteor rate: " + newZHR);

if(SporadicMeteorMgr.getFlagShow()) {
    core.debug("Sporadic meteors are visible");
} else {
    core.debug("Sporadic meteors are hidden");
    SporadicMeteorMgr.setFlagShow(true);
    core.debug("Enabled sporadic meteors");
}

// Enable sporadic meteor display
SporadicMeteorMgr.setFlagShow(true);

// Hide all sporadic meteors
SporadicMeteorMgr.setFlagShow(false);

// Toggle current state
var currentState = SporadicMeteorMgr.getFlagShow();
SporadicMeteorMgr.setFlagShow(!currentState);

// Set slow meteors (like Draconids)
SporadicMeteorMgr.setMaxVelocity(18);

// Set fast meteors (like Leonids)
SporadicMeteorMgr.setMaxVelocity(71);

// Default speed range (11-72 km/s)
SporadicMeteorMgr.setMaxVelocity(72);

if(SporadicMeteorMgr.getFlagForcedMeteorsActivity()) {
    core.debug("Meteors will show even when atmosphere is disabled");
} else {
    core.debug("Meteors only show when atmosphere is enabled");
}

// Force meteors to show even without atmosphere (planetarium mode)
SporadicMeteorMgr.setFlagForcedMeteorsActivity(true);

// Default behavior: meteors only when atmosphere is on
SporadicMeteorMgr.setFlagForcedMeteorsActivity(false);

// Disable atmosphere but keep meteors (with forced activity)
LandscapeMgr.setFlagAtmosphere(false);
SporadicMeteorMgr.setFlagForcedMeteorsActivity(true);
SporadicMeteorMgr.setFlagShow(true);
SporadicMeteorMgr.setZHR(20);
